function maxNumberOfBalloons(text) {
    let freqs = Array(26).fill(0);
    for (let c of text) {
        freqs[c.charCodeAt(0) - 'a'.charCodeAt(0)]++;
    }
    let subs = [freqs['b'.charCodeAt(0) - 'a'.charCodeAt(0)], freqs['a'.charCodeAt(0) - 'a'.charCodeAt(0)], Math.floor(freqs['l'.charCodeAt(0) - 'a'.charCodeAt(0)] / 2), Math.floor(freqs['o'.charCodeAt(0) - 'a'.charCodeAt(0)] / 2), freqs['n'.charCodeAt(0) - 'a'.charCodeAt(0)]];
    return Math.min(...subs);
}
```


    1. Create a frequency array `freqs` that counts the occurrences of each lowercase character in the given text.
2. Prepare another array `subs` containing the number of occurrences of 'b', 'a', number of occurrences of 'l' divided by 2, number of occurrences of 'o' divided by 2, and number of occurrences of 'n'. This is because there are 2 'l's and 2 'o's in the word "balloon".
3. Return the minimum value among the elements in the `subs` array as this represents the bottleneck in forming the maximum number of occurrences of the word "balloon".

