public int maxNumberOfBalloons(String text) {
    int[] freqs = new int[26];
    for (char c : text.toCharArray()) {
        freqs[c - 'a']++;
    }
    int[] subs = {freqs['b' - 'a'], freqs['a' - 'a'], freqs['l' - 'a'] / 2, freqs['o' - 'a'] / 2, freqs['n' - 'a']};
    return Arrays.stream(subs).min().getAsInt();
}
```


